import { describe, expect, test } from "bun:test"
import { execSync } from "node:child_process"
import { existsSync, readFileSync } from "node:fs"
import { join } from "node:path"

const DEMO_ROOT = join(import.meta.dir, "../../..")
const REPO_ROOT = join(DEMO_ROOT, "..", "..")

function runRg(pattern: string, cwd: string): string {
  try {
    return execSync(`rg -n "${pattern}" src --glob '*.{ts,tsx}'`, {
      cwd,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    })
  } catch {
    return ""
  }
}

describe("atoms structure guard", () => {
  test("AtomProvider exists as a client provider", () => {
    const providerPath = join(DEMO_ROOT, "src/providers/AtomProvider.tsx")
    expect(existsSync(providerPath)).toBe(true)

    const content = readFileSync(providerPath, "utf8")
    expect(content).toContain('"use client"')
    expect(content).toContain("@effect-atom/atom-react")
    expect(content).toContain("RegistryProvider")
  })

  test("layout wraps children with AtomProvider", () => {
    const layoutPath = join(DEMO_ROOT, "src/app/layout.tsx")
    const content = readFileSync(layoutPath, "utf8")
    expect(content).toContain("AtomProvider")
    expect(content).toContain("<AtomProvider>{children}</AtomProvider>")
  })

  test("atoms barrel file is absent", () => {
    const atomsIndex = join(DEMO_ROOT, "src/atoms/index.ts")
    expect(existsSync(atomsIndex)).toBe(false)
  })

  test("codebase does not import atoms via barrels", () => {
    const matches = runRg("from ['\\\"]@/atoms['\\\"]", DEMO_ROOT)
    expect(matches).toBe("")
  })

  test("gitignore blocks Next build output", () => {
    const gitignorePath = join(REPO_ROOT, ".gitignore")
    const content = readFileSync(gitignorePath, "utf8")
    expect(content).toContain("apps/demo/.next/")
  })

  test("legacy atoms test directory is removed", () => {
    expect(existsSync(join(DEMO_ROOT, "tests/atoms"))).toBe(false)
  })
})
